class Solution {
public:
    int minLength(string s) {
        vector<char> stack;
        for (char c : s) {
            stack.push_back(c);
            while (stack.size() >= 2) {
                char a = stack[stack.size()-2];
                char b = stack[stack.size()-1];
                if ((a == 'A' && b == 'B') || (a == 'C' && b == 'D')) {
                    stack.pop_back();
                    stack.pop_back();
                } else {
                    break;
                }
            }
        }
        return stack.size();
    }
};

